const fs = require('fs');
const path = require('path');

function readLogFile(filename, callback) {
  const filePath = path.resolve(__dirname, filename);
  fs.readFile(filePath, 'utf8', (err, data) => {
    if (err) return callback(err);
    callback(null, data);
  });
}